INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1516, 195807, 5, 1378, '想', '一直一直在努力的忘记，可是总有触动心弦的时候。也许是别人不经意的一句话，也许是一首曾经一起听过的歌，也许是曾经一起散步过的路。疯狂的想你，到处找你的身影你的痕迹。想证明你的存在，可是你消失的那样彻底，没有一丝的痕迹，让我不禁怀疑你是否真的出现过。也许是时间还未发挥的功能，所以至今我不能忘记你。', '一直一直在努力的忘记，可是总有触动心弦的时候。也许是别人不经意的一句话，也许是一首曾经一起听过的歌，也许是曾经一起散步过的路。疯狂的想你，到处找你的身影你的痕迹。想证明你的存在，可是你消失的那样彻底，没有一丝的痕迹，让我不禁怀疑你是否真的出现过。也许是时间还未发挥的功能，所以至今我不能忘记你。', NULL, '2003-02-08 15:35:00', 7, '20030312131840_bbsid_195807_board_5_06efd5f976.html', '20030312131840');
